// Parse the ListObjectsV2 XML response from MinIO into structured items.
// We avoid xml2js (not in the n8n sandbox) and use regex extraction.
const raw = $input.first().json;
const body = typeof raw === 'string' ? raw : (raw.data || raw.body || '');
if (!body || typeof body !== 'string') {
  return [{ json: { _noFiles: true, total: 0, debug: 'empty response body' } }];
}
const items = [];
const contentRe = /<Contents>([\s\S]*?)<\/Contents>/g;
let m;
while ((m = contentRe.exec(body)) !== null) {
  const block = m[1];
  const key = (block.match(/<Key>([^<]+)<\/Key>/) || [])[1];
  const size = parseInt((block.match(/<Size>([^<]+)<\/Size>/) || [])[1] || '0', 10);
  const lastModified = (block.match(/<LastModified>([^<]+)<\/LastModified>/) || [])[1];
  if (!key) continue;
  items.push({ Key: key, Size: size, LastModified: lastModified });
}
if (items.length === 0) {
  return [{ json: { _noFiles: true, total: 0 } }];
}
return items.map(it => ({ json: it }));

// Filter to only real .md files (exclude zero-byte and folder placeholders).
const items = $input.all();
const files = items.filter(item => {
  if (item.json._noFiles) return false;
  const key = item.json.Key || '';
  const size = item.json.Size || 0;
  return key.endsWith('.md') && size > 0;
});
return files.length > 0 ? files : [{ json: { _noFiles: true } }];

// Parse sections, detect real content, extract tasks via broader regex heuristic.
// Mirrors tools/process_brain_dump.py — handles operator's prose patterns:
// 'Flush out X', 'Fine Tune X', 'Re-apply X', 'Dig into X' AND `- YYYYMMDD`
// shorthand date suffix.
const item = $input.first();
let content = '';
try {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  content = buf.toString('utf-8');
} catch (e) {
  return [{ json: { hasContent: false } }];
}
const fileName = item.json.Key?.split('/').pop() || '';
const today = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Chicago' });

// ── Helpers ─────────────────────────────────────────────────────────────
function inferArea(name) {
  const n = name.toLowerCase();
  if (n.includes('faith') || n.includes('bible')) return 'faith';
  if (n.includes('family')) return 'family';
  if (n.includes('business') || n.includes('echelon') || n.includes('website')) return 'business';
  if (n.includes('consulting')) return 'consulting';
  if (n.includes('work') || n.includes('parallon')) return 'work';
  if (n.includes('health')) return 'health';
  if (n.includes('home')) return 'home';
  if (n.includes('coding')) return 'personal';
  return 'personal';
}

// `- YYYYMMDD` (or `— YYYYMMDD`) trailing shorthand → `[due:: YYYY-MM-DD]`
const SHORTHAND_DATE_RE = /\s*[-—]\s*(\d{4})(\d{2})(\d{2})\s*$/;
function normalizeShorthandDates(text) {
  const m = SHORTHAND_DATE_RE.exec(text);
  if (!m) return text;
  const yyyy = parseInt(m[1], 10), mm = parseInt(m[2], 10), dd = parseInt(m[3], 10);
  // Validate as a real date.
  const d = new Date(Date.UTC(yyyy, mm - 1, dd));
  if (d.getUTCFullYear() !== yyyy || d.getUTCMonth() !== mm - 1 || d.getUTCDate() !== dd) return text;
  return text.replace(SHORTHAND_DATE_RE, ` [due:: ${m[1]}-${m[2]}-${m[3]}]`);
}

function isEmpty(body) {
  const stripped = body
    .replace(/<!--[\s\S]*?-->/g, '')
    .replace(/^\s*[-*]{3,}\s*$/gm, '')
    .replace(/^\s*=this\.\w+\s*$/gm, '')
    .replace(/^\s*\*[^*]+\*\s*$/gm, '')
    .replace(/^\s*>.*$/gm, '')
    .replace(/^\s*$/gm, '')
    .trim();
  return stripped.length === 0;
}

const Q2 = {
  faith: ['bible', 'bible study', 'social media', 'church', 'prayer'],
  family: ['christy', 'marriage', 'questionnaire', 'kids'],
  business: ['echelon', 'website', 'offer', 'outreach', 'mvp', 'temple protocol', 'e7'],
  work: ['union', 'parallon', 'deliver', 'exit'],
  health: ['hip', 'gym', 'crossfit', 'workout', '3x']
};
function inferPriority(text) {
  const l = text.toLowerCase();
  for (const kws of Object.values(Q2)) {
    if (kws.some(k => l.includes(k))) return 'A';
  }
  return 'B';
}

const EXPLORE_RE = /\b(research|investigate|explore|look\s+into|dig\s+into|study|evaluate|deep\s+dive)\b/i;
function explorePart(desc) { return EXPLORE_RE.test(desc) ? ' [explore:: true]' : ''; }

const IMPERATIVE_LEAD_RE = /^([A-Z][a-z]+(?:[-\s][A-Za-z]+)?)\b/;
const BLOCKLIST = ['## ', '# ', '*Tags:', '*Last', '*Updated', 'Format:', 'How to use'];
function isImperativeProse(line) {
  if (line.length < 10) return false;
  if (BLOCKLIST.some(b => line.startsWith(b))) return false;
  if (line.startsWith('#') || line.startsWith('|')) return false;
  if (/^[Ii]\s+(need|should|must|want|have)\s+to\b/.test(line)) return true;
  if (/^Need\s+to\b/i.test(line)) return true;
  return IMPERATIVE_LEAD_RE.test(line);
}

function inferDue(raw) {
  const m = raw.match(/\[due::\s*(\d{4}-\d{2}-\d{2})\]/);
  return m ? m[1] : null;
}
function cleanText(raw) {
  return raw.replace(/\s*\[(area|priority|due)::[^\]]*\]/g, '').trim();
}
function buildTask(desc, area, priority, due, explore) {
  let t = `- [ ] ${desc} [area:: ${area}] [priority:: ${priority}]`;
  if (due) t += ` [due:: ${due}]`;
  if (explore || EXPLORE_RE.test(desc)) t += ' [explore:: true]';
  return t;
}

// ── Parse sections ──────────────────────────────────────────────────────
const sections = {};
let header = '_fm';
let lines = [];
for (const line of content.split('\n')) {
  if (line.trim().startsWith('## ')) {
    sections[header] = lines.join('\n');
    header = line.trim().substring(3).trim();
    lines = [];
  } else {
    lines.push(line);
  }
}
sections[header] = lines.join('\n');

const area = inferArea(fileName);
const tasks = [];
const articles = [];
const extractedHeaders = [];

for (const [h, body] of Object.entries(sections)) {
  if (h.startsWith('_') || isEmpty(body)) continue;
  const isTask = /To Do|Needle|Recurring|Organize/i.test(h);
  const isArticle = /Article|Resource/i.test(h);
  if (!isTask && !isArticle && !/Quick Notes|Ideas/i.test(h)) continue;
  extractedHeaders.push(h);

  if (isTask) {
    for (const rawLine of body.split('\n')) {
      const normalized = normalizeShorthandDates(rawLine.trim());
      const s = normalized;
      if (!s || s.startsWith('<!--') || s.startsWith('>') || /^\*[^*]+\*$/.test(s)) continue;

      let taskText = '';
      // existing - [ ] checkbox
      if (/^[-*]\s*\[ \]\s+/.test(s)) {
        taskText = s.replace(/^[-*]\s*\[ \]\s+/, '');
      // bullet without checkbox
      } else if (/^[-*]\s+\S/.test(s)) {
        taskText = s.replace(/^[-*]\s+/, '');
      // explicit priority suffix "... - A"
      } else if (/.{10,}\s+-\s+[ABC](\s*-\s*due\s+\d{4}-\d{2}-\d{2})?$/.test(s)) {
        const pm = s.match(/\s+-\s+([ABC])(?:\s+-\s+due\s+(\d{4}-\d{2}-\d{2}))?$/);
        if (pm) {
          const explicitP = pm[1];
          const dueDate = pm[2];
          const desc = cleanText(s.substring(0, pm.index).trim());
          if (desc.length >= 5) tasks.push(buildTask(desc, area, explicitP, dueDate));
        }
        continue;
      // imperative-prose heuristic (Title-case lead, length ≥ 10)
      } else if (isImperativeProse(s)) {
        taskText = s;
      }

      if (taskText && taskText.length > 5) {
        const due = inferDue(taskText);
        const desc = cleanText(taskText);
        if (!desc) continue;
        const priority = inferPriority(desc);
        tasks.push(buildTask(desc, area, priority, due));
      }
    }
  }
  if (isArticle) {
    const urls = body.match(/https?:\/\/[^\s\)\]]+/g) || [];
    for (const url of urls) if (url.length > 10) articles.push(`- <${url}>`);
  }
}

return [{ json: {
  hasContent: tasks.length > 0 || articles.length > 0 || extractedHeaders.length > 0,
  hasExtracted: tasks.length > 0 || articles.length > 0,
  fileName, fileKey: item.json.Key, area, today,
  tasks, articles, taskCount: tasks.length, articleCount: articles.length,
  extractedHeaders, content
}}];

const item = $input.first();
const { tasks, articles, fileName, area, today, content, extractedHeaders } = item.json;

const slug = fileName.replace('.md','').replace(/ /g,'-').replace(/[—–]/g,'').replace(/--+/g,'-').replace(/^-|-$/g,'');
const taskFileKey = `00_Inbox/processed/${today}-${slug}-tasks.md`;
const resetFileKey = item.json.fileKey;
const logKey = `99_System/logs/brain-dump-processor-${today}.json`;

// ── Task output file ──────────────────────────────────────────────────────
let taskFile = `---\nsource: ${fileName}\narea: ${area}\nprocessed: ${today}\ntype: extracted-tasks\n---\n\n# Extracted Tasks — ${fileName} (${today})\n\n${tasks.join('\n')}\n`;

// ── Clean template reset ──────────────────────────────────────────────────
const h1Match = content.match(/^# .+$/m);
const titleLine = h1Match ? h1Match[0] : `# Brain Dump — ${fileName.replace('.md','')}`;
const tagsMatch = content.match(/^\*Tags:.*\*$/m);
const tagsLine = tagsMatch ? tagsMatch[0] : `*Tags: #brain-dump #${area}*`;
const domainName = content.match(/^domain:\s*(.+)$/m)?.[1]?.trim() || area;

const resetContent = `---
domain: ${domainName}
area: ${area}
last_processed: ${today}
status: empty
---

${titleLine}

> **How to use:** Drop anything here — raw thoughts, ideas, tasks, links, decisions. Claude processes this into your system and clears it out. If this file is empty, it gets skipped.
> 
> **Last processed:** \`=this.last_processed\`

---

## ⚡ Quick Notes
*Raw thoughts, observations, things on your mind right now*

<!-- Add notes here -->


---

## 🎯 Needle Movers
*Big moves that could change the game — for this domain specifically*

<!-- Format: - [ ] <what> -->


---

## ✅ To Do's
*Specific actions, tasks, follow-ups*

<!-- Format: - [ ] <task> [priority:: A/B/C] [due:: YYYY-MM-DD] -->


---

## 📰 Articles & Resources to Follow Up On
*Links, articles, books, videos, tools to explore*

<!-- Format: - [ ] [Title](URL) — <why it matters> -->


---

## 🗂️ Things to Organize & Follow Up On
*Loose ends, conversations to close, things in limbo*

<!-- Add items here -->


---

## 💡 Ideas & Possibilities
*Half-baked ideas, what-ifs, experiments worth exploring*

<!-- Add ideas here -->


---

## 🔁 Recurring / Rhythms
*Regular things in this domain that need attention or a new rhythm*

<!-- Add here -->


---

${tagsLine}
`;

// ── Run log ──────────────────────────────────────────────────────────────
const log = JSON.stringify({
  workflow: 'brain-dump-processor', run_date: today,
  finished_at: new Date().toISOString(), status: 'success',
  files_with_content: 1, tasks_extracted: tasks.length,
  articles_queued: articles.length, files_processed: [fileName],
  reset_applied: true
}, null, 2);

const taskBuf  = Buffer.from(taskFile,    'utf-8');
const resetBuf = Buffer.from(resetContent,'utf-8');
const logBuf   = Buffer.from(log,         'utf-8');

return [{ json: {
  taskFileKey, articleLines: articles.join('\n'), resetFileKey, logKey,
  taskCount: tasks.length, articleCount: articles.length, fileName, today
}, binary: {
  taskFile:  { data: taskBuf.toString('base64'),  mimeType: 'text/markdown; charset=utf-8', fileName: taskFileKey.split('/').pop(), fileExtension: 'md', fileSize: taskBuf.length  },
  resetFile: { data: resetBuf.toString('base64'), mimeType: 'text/markdown; charset=utf-8', fileName: resetFileKey.split('/').pop(), fileExtension: 'md', fileSize: resetBuf.length },
  logFile:   { data: logBuf.toString('base64'),   mimeType: 'application/json',             fileName: logKey.split('/').pop(),       fileExtension: 'json', fileSize: logBuf.length   }
}}];

// Defense-in-depth: even a true zero-files run writes a run log AND emits
// an alert payload so silent zeros never happen again.
const today = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Chicago' });
const log = JSON.stringify({
  workflow: 'brain-dump-processor', run_date: today,
  finished_at: new Date().toISOString(), status: 'skipped',
  skip_reason: 'source_prefix_empty',
  files_with_content: 0, tasks_extracted: 0,
  articles_queued: 0, files_processed: []
}, null, 2);
const buf = Buffer.from(log, 'utf-8');
const logKey = `99_System/logs/brain-dump-processor-${today}.json`;
return [{ json: { logKey, today, status: 'skipped', skip_reason: 'source_prefix_empty' }, binary: { logFile: { data: buf.toString('base64'), mimeType: 'application/json', fileName: logKey.split('/').pop(), fileExtension: 'json', fileSize: buf.length } } }];

// Read current MTL and append new tasks (with dedup)
const parseOutput = $('Parse & Extract').first().json;
const buildOutput = $('Build Output Files').first().json;
const tasks = parseOutput.tasks || [];
const today = buildOutput.today || parseOutput.today;
const fileName = buildOutput.fileName || parseOutput.fileName;

if (!tasks || tasks.length === 0) {
  return [{ json: { mtlUpdated: false, reason: 'no tasks to append' } }];
}

// Read MTL content from binary
let mtlContent = '';
try {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  mtlContent = buf.toString('utf-8');
} catch(e) {
  // MTL read failed — still proceed, just can't dedup
  mtlContent = '';
}

// Dedup: extract existing task descriptions
const existing = new Set();
for (const line of mtlContent.split('\n')) {
  const m = line.match(/^- \[[ x]\] (.+?)(?:\s*\[area::|\s*$)/);
  if (m) existing.add(m[1].trim().toLowerCase());
}

const newTasks = tasks.filter(t => {
  const m = t.match(/^- \[ \] (.+?)(?:\s*\[area::|\s*$)/);
  if (!m) return true;
  const desc = m[1].trim().toLowerCase();
  if (existing.has(desc)) return false;
  existing.add(desc);
  return true;
});

if (newTasks.length === 0) {
  return [{ json: { mtlUpdated: false, reason: 'all tasks already in MTL (deduped)' } }];
}

// Append
const appendBlock = `\n\n## Brain Dump Capture — ${today} (${fileName})\n${newTasks.join('\n')}\n`;
const updatedMtl = mtlContent.trimEnd() + appendBlock;
const buf = Buffer.from(updatedMtl, 'utf-8');

return [{ json: {
  mtlUpdated: true, tasksAppended: newTasks.length, totalTasks: tasks.length
}, binary: {
  mtlFile: { data: buf.toString('base64'), mimeType: 'text/markdown; charset=utf-8', fileName: '!!! MASTER TASK LIST.md', fileExtension: 'md', fileSize: buf.length }
}}];
